import React, { useState, useEffect } from 'react';
import './Clothing.css'; 
import { useCart } from '../Context/CartContext';
import ProductService from '../Services/ProductService';

function KidsClothing() {
  const [clothingItems, setClothingItems] = useState([]);
  const [selectedItem, setSelectedItem] = useState(null);
  const [loading, setLoading] = useState(true);
  const [showNotification, setShowNotification] = useState(false);
  const [notificationMessage, setNotificationMessage] = useState('');
  const { addToCart } = useCart();

  useEffect(() => {
    const fetchClothingItems = async () => {
      try {
        const clothingSnapshot = await ProductService.getProductsByCategoryAndSubcategory('Clothing', 'Kids');
        const clothingList = clothingSnapshot.docs.map(doc => ({
          id: doc.id,
          ...doc.data()
        }));
        setClothingItems(clothingList);
      } catch (error) {
        console.error("Error fetching kids' clothing items:", error);
      } finally {
        setLoading(false);
      }
    };

    fetchClothingItems();
  }, []);

  const handleAddToCart = (item) => {
    addToCart(item, 1, 1);
    setNotificationMessage(`${item.name} has been added to your cart!`);
    setShowNotification(true);
    setTimeout(() => {
      setShowNotification(false);
    }, 3000); 
  };

  const handleItemClick = (item) => {
    setSelectedItem(item);
  };

  const handleClosePopup = () => {
    setSelectedItem(null);
  };

  if (loading) {
    return <p>Loading kids' clothing items...</p>;
  }

  return (
    <div className="Clothing">
      <h2>Kids' Clothing</h2>
      <p>Find durable and comfortable outdoor clothing for kids of all ages.</p>
      <div className="clothing-list">
        {clothingItems.map((item) => (
          <div key={item.id} className={`clothing-item ${item.newArrival ? 'new-arrival' : ''}`}>
            {item.newArrival && <span className="new-badge">New Arrival</span>}
            <img src={item.mainImage} alt={item.name} />
            <h3 onClick={() => handleItemClick(item)} className="item-name-clickable">
              {item.name}
            </h3>
            <p>{item.description}</p>
            <p className="price">${item.pricePerDay}/day</p>
            <button className="confirm-btn" onClick={() => handleAddToCart(item)}>
              Add to Cart
            </button>
          </div>
        ))}
      </div>

      {selectedItem && (
        <div className="popup" onClick={handleClosePopup}>
          <div className="popup-content" onClick={(e) => e.stopPropagation()}>
            <span className="close-btn" onClick={handleClosePopup}>&times;</span>
            <h2>{selectedItem.name}</h2>
            <p>{selectedItem.description}</p>
            <div className="popup-images">
              {selectedItem.additionalImages && selectedItem.additionalImages.length > 0 ? (
                selectedItem.additionalImages.map((image, index) => (
                  <img key={index} src={image} alt={`${selectedItem.name} - ${index + 1}`} />
                ))
              ) : (
                <p>No additional images available</p>
              )}
            </div>
          </div>
        </div>
      )}

      {showNotification && (
        <div className="notification">
          {notificationMessage}
        </div>
      )}
    </div>
  );
}

export default KidsClothing;
